const crypto = require('crypto');
function generateRequestHash(obj, secretKey) {
  // Sort object keys to ensure consistency
  const sortedKeys = Object.keys(obj).sort();

  // Convert object to a consistent string format
  const dataString = sortedKeys
    .map((key) => `${key}:${JSON.stringify(obj[key])}`)
    .join('|');

  // Create HMAC hash using the secret key
  return crypto
    .createHmac('sha256', secretKey)
    .update(dataString)
    .digest('hex');
}
